CREATE PROCEDURE test_delete_snapshot()
{
  DECLARE access_key VARCHAR;
  DECLARE sec_token VARCHAR;
  DECLARE snapshotId VARCHAR;
  SET access_key := (SELECT access_key FROM snapshots WHERE size > 50 LIMIT 1);
  SET sec_token := (SELECT sec_token FROM snapshots WHERE snapshotId = 'snap-1a2b3c4d');
  SET snapshotId := (SELECT snapshotId FROM snapshots WHERE access_key = 'AKIAXXXXXX');
  IF snapshotId > '' THEN
    DB.DBA.AMAZON_DELETE_SNAPSHOT(access_key, snapshotId, sec_token);
  END IF;
};
